    };

    const state = { ...DEFAULTS };
    const baseTransform = {};
    const basePath = {};
    const baseHandPath = {};
    let leftTurnTargetSvg = null;
    let idleSourceSvg = null;
    let rawAnchors = {};
    let startAnchors = {};
    let endAnchors = {};
