    let lastTs = 0;

    const sliders = [
      "progress", "speed",
      "mailStartX", "mailStartY", "mailLookX", "mailLookY", "waveAngle", "waveLift", "waveBalance", "waveBody",
      "reachRise", "reachShift", "reachLean", "headExtraLift",
