      "balanceHandX", "catchHandX", "catchHandY", "catchHandRotate", "balanceHandY", "balanceHandRotate",
      "mailApproachX", "mailApproachY"
    ];
    const checks = ["darkStage", "showEnvelope", "showTrail", "showGuides", "showLabels", "showOriginalHands", "dimFace"];


  const EXPORT_DURATION_MS = 3333.333;
  const BAKED_RAW_ANCHORS = {"A":{"x":65,"y":153,"label":"左边界"},"L":{"x":137.77,"y":162.56,"label":"左弧低点"},"C":{"x":171.37,"y":154.02,"label":"鼻梁左"},"D":{"x":189.69,"y":147.65,"label":"鼻梁峰"},"E":{"x":210.43,"y":157.48,"label":"鼻梁右"},"R":{"x":240.66,"y":162.63,"label":"右弧低点"},"G":{"x":309,"y":153,"label":"右边界"},"B":{"x":138,"y":157,"label":"左眼中心"},"F":{"x":237,"y":157,"label":"右眼中心"},"N":{"x":187,"y":170,"label":"鼻中心"},"J":{"x":187,"y":177,"label":"鼻下"},"ML":{"x":163,"y":192,"label":"嘴左端"},"MR":{"x":211,"y":192,"label":"嘴右端"},"BL":{"x":92,"y":185,"label":"左腮红"},"BR":{"x":281,"y":185,"label":"右腮红"},"H":{"x":187,"y":48,"label":"头顶"},"T":{"x":203,"y":16,"label":"呆毛"},"EL":{"x":101,"y":73,"label":"左耳"},"ER":{"x":286,"y":73,"label":"右耳"},"LS":{"x":62,"y":238,"label":"左腮影起"},"LC1":{"x":70,"y":250,"label":"左腮影控1"},"LC2":{"x":84,"y":256,"label":"左腮影控2"},"LE":{"x":100,"y":256,"label":"左腮影止"},"RS":{"x":312,"y":238,"label":"右腮影起"},"RC1":{"x":304,"y":250,"label":"右腮影控1"},"RC2":{"x":290,"y":256,"label":"右腮影控2"},"RE":{"x":274,"y":256,"label":"右腮影止"},"ELR":{"x":88,"y":102,"label":"左耳根"},"ELC":{"x":101,"y":73,"label":"左耳心"},"ELI":{"x":101,"y":73,"label":"左内耳"},"ERR":{"x":274,"y":102,"label":"右耳根"},"ERC":{"x":286,"y":73,"label":"右耳心"},"ERI":{"x":286,"y":73,"label":"右内耳"},"TLR":{"x":182,"y":49,"label":"左呆毛根"},"TLC":{"x":184,"y":35,"label":"左呆毛控"},"TLT":{"x":192,"y":15,"label":"左呆毛尖"},"TRR":{"x":200,"y":50,"label":"右呆毛根"},"TRC":{"x":203,"y":34,"label":"右呆毛控"},"TRT":{"x":214,"y":16,"label":"右呆毛尖"}};
  const BAKED_TURN_TARGET = {"headCapD":"M64.00 153.00 C45.52 88.00 106.76 48.00 187.00 48.00 C256.45 49.81 307.88 89.55 310.00 153.00 C310 214 257 253 187 253 C117 253 64 214 64 153Z","cheekD":"M65 153 C69.14 154.15 92.2 162.44 99.48 162.56 C105.73 162.66 121.22 155.55 125.72 154.02 C130.21 152.49 139.09 147.29 143.22 147.65 C147.34 148.01 159.58 155.94 165.82 157.48 C172.06 159.02 189.15 163.09 203.88 162.63 C221.06 162.09 296.39 154.16 309 153 C320.06 180.73 321.87 218.27 303.00 246.00 C270.00 268.00 104.00 268.00 71.00 246.00 C35.12 221.00 40.60 178.00 65.00 153.00Z","leftCreaseD":"M64.54 238.22 C70.60 243.25 78.38 247.59 96.39 252.92","rightCreaseD":"M305.37 238.22 C302.16 243.65 295.62 247.59 277.61 252.92","mouthLeftD":"M187.00 177.00 C187.00 190.00 181.05 198.00 173.40 198.00 C169.15 198.00 166.60 195.00 166.60 192.00","mouthRightD":"M187.00 177.00 C187.00 190.00 194.00 198.00 203.00 198.00 C208.00 198.00 211.00 195.00 211.00 192.00"};
  let exportRafId = 0;
  let exportStartMs = 0;
  let exportPaused = false;
  let exportPausedAt = 0;
  let exportPausedTotal = 0;

  function bootExport() {
    svg = document.currentScript && document.currentScript.ownerSVGElement
      ? document.currentScript.ownerSVGElement
      : (document.querySelector("svg") || document.documentElement);
    idleSourceSvg = svg.querySelector("#notification-idle-source");
    prepareHeadPoseLayer();
    prepareBlushClip(svg);
    prepareMouthRig();
    rawAnchors = BAKED_RAW_ANCHORS;
    startAnchors = rawAnchors;
    endAnchors = buildEndAnchors(rawAnchors);
    turnBase = captureTurn(svg);
    turnTarget = BAKED_TURN_TARGET;
    state.progress = 0;
    state.showEnvelope = true;
    state.showTrail = false;
    state.showGuides = false;
    state.showLabels = false;
    state.showOriginalHands = false;
    state.dimFace = false;
    rememberBase();
    render();
    svg.addEventListener("cloudling:set-notification-progress", function () {
      const value = Number(svg.getAttribute("data-force-progress"));
      if (!Number.isFinite(value)) return;
      state.progress = ((value % 100) + 100) % 100;
      render();
    });
    exportStartMs = performance.now();
    exportLoop(exportStartMs);
  }

  function exportLoop(now) {
    exportRafId = 0;
    if (exportPaused) return;
    const elapsed = now - exportStartMs - exportPausedTotal;
    const phase = ((elapsed % EXPORT_DURATION_MS) + EXPORT_DURATION_MS) % EXPORT_DURATION_MS;
    state.progress = phase / EXPORT_DURATION_MS * 100;
    render();
    exportRafId = requestAnimationFrame(exportLoop);
  }

  function scheduleExportLoop() {
    if (!exportPaused && !exportRafId) exportRafId = requestAnimationFrame(exportLoop);
  }

  window.__clawdSetLowPowerPaused = function (paused) {
    const next = !!paused;
    if (exportPaused === next) return;
    exportPaused = next;
    if (next) {
      exportPausedAt = performance.now();
      if (exportRafId) cancelAnimationFrame(exportRafId);
      exportRafId = 0;
      return;
    }
    if (exportPausedAt) exportPausedTotal += performance.now() - exportPausedAt;
    exportPausedAt = 0;
    scheduleExportLoop();
  };

  window.__cloudlingReplayNotification = function () {
    exportPausedTotal = 0;
    exportPausedAt = 0;
    exportStartMs = performance.now();
    state.progress = 0;
    render();
    scheduleExportLoop();
  };

function applyStageTheme() {}

    function rememberBase() {
      [
        "body-layer", "tail", "tie", "feet-layer", "left-foot", "right-foot",
        "tie-shadow", "tie-knot", "tie-blade", "tie-knot-highlight", "tie-center-fold", "tie-left-fold",
        "notification-head-pose-layer"
      ].forEach((id) => {
        const node = svg.querySelector(`#${id}`);
        if (node) baseTransform[id] = node.getAttribute("transform") || "";
      });
      ["body-belly-fill", "left-foot-fill", "right-foot-fill"].forEach((id) => {
        const node = svg.querySelector(`#${id}`);
        if (node) basePath[id] = node.getAttribute("d") || "";
      });
      Object.values(HAND_IDS).flat().forEach((id) => {
        const node = svg.querySelector(`#${id}`);
        if (node) baseHandPath[id] = node.getAttribute("d") || "";
      });
    }

    function prepareHeadPoseLayer() {
      const rootGroup = svg.querySelector("#hamster-flat-master-v11") || svg;
      if (rootGroup.querySelector("#notification-head-pose-layer")) return;
      const nodes = HEAD_IDS.map((id) => svg.querySelector(`#${id}`)).filter(Boolean);
      if (!nodes.length) return;
      const wrapper = el("g", {
        id: "notification-head-pose-layer",
        "data-layer": "notification-whole-head-pose"
      });
      rootGroup.insertBefore(wrapper, nodes[0]);
      nodes.forEach((node) => wrapper.appendChild(node));
      baseTransform["notification-head-pose-layer"] = "";
    }

    function parseSvg(text, label) {
      const doc = new DOMParser().parseFromString(text, "image/svg+xml");
      if (doc.querySelector("parsererror")) throw new Error(`${label} 解析失败`);
      return document.importNode(doc.documentElement, true);
    }

    function ensureDefs(root) {
      let defs = root.querySelector("defs");
      if (!defs) {
        defs = el("defs");
        root.insertBefore(defs, root.firstElementChild);
      }
      return defs;
    }

    function prepareBlushClip(root) {
      const blushes = root.querySelector("#blushes");
      const faceLayer = root.querySelector("#face-layer");
      if (!blushes || !faceLayer || root.querySelector("#left-turn-blush-clip-wrapper")) return;

      const defs = ensureDefs(root);
      const clip = el("clipPath", { id: "left-turn-blush-clip", clipPathUnits: "userSpaceOnUse" });
      const clipPath = el("path", { id: "left-turn-blush-clip-path" });
      clip.appendChild(clipPath);
      defs.appendChild(clip);

      const wrapper = el("g", {
        id: "left-turn-blush-clip-wrapper",
        "data-layer": "notification-left-turn-blush-clip",
        "clip-path": "url(#left-turn-blush-clip)"
      });
      const transformGroup = el("g", { id: "left-turn-blush-transform" });
      transformGroup.appendChild(blushes);
      wrapper.appendChild(transformGroup);
      faceLayer.parentNode.insertBefore(wrapper, faceLayer);
    }

    function prepareMouthRig() {
      const noseMouth = svg.querySelector("#nose-mouth");
      const nose = svg.querySelector("#nose-fill");
      const left = svg.querySelector("#mouth-left");
      const right = svg.querySelector("#mouth-right");
      if (!noseMouth || !nose || !left || !right || svg.querySelector("#mouth-interior-clipped")) return;

      const defs = ensureDefs(svg);
      const clip = el("clipPath", { id: "notification-mouth-opening-clip", clipPathUnits: "userSpaceOnUse" });
      clip.appendChild(el("path", { id: "mouth-opening-clip-path" }));
      defs.appendChild(clip);

      const interior = el("g", {
        id: "mouth-interior-clipped",
        "data-role": "happy-mouth-interior-clipped",
        "clip-path": "url(#notification-mouth-opening-clip)"
      });
      interior.appendChild(el("path", {
        id: "mouth-cavity-fill",
        fill: "#8c2f2a"
      }));
      interior.appendChild(el("path", {
        id: "mouth-lower-cavity-fill",
        fill: "#f58d86"
      }));

      const strokes = el("g", {
        id: "mouth-visible-strokes",
        "data-role": "happy-mouth-visible-w-strokes"
      });
      strokes.appendChild(left);
      strokes.appendChild(right);
      noseMouth.insertBefore(interior, nose.nextSibling);
      noseMouth.appendChild(strokes);
    }

    function prepareIdleBackHandDefs() {
      if (!idleSourceSvg) return;
      const defs = ensureDefs(svg);
      ["idle-hand-shadow-clip-left", "idle-hand-shadow-clip-right"].forEach((id) => {
        if (svg.querySelector(`#${id}`)) return;
        const clip = idleSourceSvg.querySelector(`#${id}`);
        if (clip) defs.appendChild(clip.cloneNode(true));
      });
    }

    function attr(root, id, name) {
      return root.querySelector(`#${id}`)?.getAttribute(name) || "";
    }

    function captureTurn(root) {
      return {
        headCapD: attr(root, "head-cap-fill", "d"),
        cheekD: attr(root, "cheek-muzzle-fill", "d"),
        leftCreaseD: attr(root, "left-cheek-crease", "d"),
        rightCreaseD: attr(root, "right-cheek-crease", "d"),
        mouthLeftD: attr(root, "mouth-left", "d"),
        mouthRightD: attr(root, "mouth-right", "d")
      };
    }

    function flattenAnchors(data) {
      const points = {};
      (data.groups || []).forEach((group) => {
        (group.anchors || []).forEach((anchor) => {
          points[anchor.id] = { x: Number(anchor.x), y: Number(anchor.y), label: anchor.label || anchor.id };
        });
      });
      return points;
    }

    function transformTopPoint(point) {
      const axisX = SIDE_TOP.headAxisX;
      const axisTravel = (axisX - 187) * SIDE_TOP.muzzleFollow;
      const localX = point.x - axisX;
      const next = { x: axisTravel + axisX + localX, y: point.y };
      const a = rawAnchors.A || { x: 65 };
      const g = rawAnchors.G || { x: 309 };
      const weightT = clamp((point.x - a.x) / (g.x - a.x), 0, 1);
      const weight = Math.pow(Math.sin(Math.PI * weightT), 0.9);
      return {
        x: point.x + (next.x - point.x) * weight,
        y: point.y
      };
    }

    function buildEndAnchors(points) {
      const result = {};
      SHOWN_ANCHORS.forEach((id) => {
        if (!points[id]) return;
        if (TOP_CHAIN.includes(id) || id === "B" || id === "F") {
          result[id] = transformTopPoint(points[id]);
          return;
        }
        result[id] = SIDE_HEAD_POINTS[id] || points[id];
      });
      return result;
    }

    function numbers(text) {
      return (text.match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi) || []).map(Number);
    }

    function interpolateNumberString(from, to, t) {
      const a = numbers(from);
      const b = numbers(to);
      let i = 0;
      if (!from || !to || a.length !== b.length) return t < 1 ? from : to;
      return from.replace(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi, () => fmt(lerp(a[i], b[i++])));

      function lerp(x, y) {
        return x + (y - x) * t;
      }
    }

    function catmullPath(points, tension = 0.72, sharpness = 0.34) {
      const segs = [`M${fmt(points[0].x)} ${fmt(points[0].y)}`];
      for (let i = 0; i < points.length - 1; i += 1) {
        const p0 = points[Math.max(0, i - 1)];
        const p1 = points[i];
        const p2 = points[i + 1];
        const p3 = points[Math.min(points.length - 1, i + 2)];
        const nearBridge = ["C", "D", "E"].includes(p1.id) || ["C", "D", "E"].includes(p2.id);
        const localTension = tension * (nearBridge ? (1 - sharpness * 0.42) : 1);
        const c1 = {
          x: p1.x + (p2.x - p0.x) * localTension / 6,
          y: p1.y + (p2.y - p0.y) * localTension / 6
        };
        const c2 = {
          x: p2.x - (p3.x - p1.x) * localTension / 6,
          y: p2.y - (p3.y - p1.y) * localTension / 6
        };
        segs.push(`C${fmt(c1.x)} ${fmt(c1.y)} ${fmt(c2.x)} ${fmt(c2.y)} ${fmt(p2.x)} ${fmt(p2.y)}`);
      }
      return segs.join(" ");
    }

    function dynamicFacePath(t) {
      if (t <= 0.001) return turnBase.cheekD;
      if (t >= 0.999) return turnTarget.cheekD;
      const current = TOP_CHAIN.map((id) => ({ id, ...mixPoint(startAnchors[id], endAnchors[id], t) }));
      const top = catmullPath(current);
      const tail = FACE_TAIL_FRONT.map((seg, index) => {
        const mixed = seg.map((value, numberIndex) => value + (FACE_TAIL_SIDE[index][numberIndex] - value) * t);
        return `C${fmt(mixed[0])} ${fmt(mixed[1])} ${fmt(mixed[2])} ${fmt(mixed[3])} ${fmt(mixed[4])} ${fmt(mixed[5])}`;
      }).join(" ");
      return `${top} ${tail}Z`;
    }

    function centeredTransform(origin, next, t, scale = { x: 1, y: 1 }, rotate = 0) {
      const center = mixPoint(origin, next, t);
      const sx = 1 + (scale.x - 1) * t;
      const sy = 1 + (scale.y - 1) * t;
      const r = rotate * t;
      return `translate(${fmt(center.x)} ${fmt(center.y)}) rotate(${fmt(r)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-origin.x)} ${fmt(-origin.y)})`;
    }

    function earTransform(origin, next, t) {
      const center = mixPoint(origin, next, t);
      return `translate(${fmt(center.x - origin.x)} ${fmt(center.y - origin.y)})`;
    }

    function facePlaneTransform(t, follow = 1) {
      const tt = t * follow;
      const axis = 187 + (125 - 187) * tt;
      const dx = -46.5 * tt;
      return `translate(${fmt(dx)} 0) translate(${fmt(axis)} 172) skewX(0) scale(1 1) translate(${fmt(-axis)} -172)`;
    }

    function tuftTransform(t) {
      const axis = 198 + (125 - 198) * t;
      const dx = -21.7 * t;
      return `translate(${fmt(dx)} 0) translate(${fmt(axis)} 54) skewX(0) scale(1 1) translate(${fmt(-axis)} -54)`;
    }

    function setTurnAttr(id, name, value) {
      const node = svg?.querySelector(`#${id}`);
      if (!node) return;
      if (value) node.setAttribute(name, value);
      else node.removeAttribute(name);
    }

    function applyLeftTurn(turn) {
      if (!turnBase.cheekD || !turnTarget.cheekD) return;
      const t = smooth(clamp(turn, 0, 1));
      setTurnAttr("head-cap-fill", "d", interpolateNumberString(turnBase.headCapD, turnTarget.headCapD, t));
      setTurnAttr("cheek-muzzle-fill", "d", dynamicFacePath(t));
      setTurnAttr("left-cheek-crease", "d", interpolateNumberString(turnBase.leftCreaseD, turnTarget.leftCreaseD, t));
      setTurnAttr("right-cheek-crease", "d", interpolateNumberString(turnBase.rightCreaseD, turnTarget.rightCreaseD, t));
      setTurnAttr("mouth-left", "d", interpolateNumberString(turnBase.mouthLeftD, turnTarget.mouthLeftD, t));
      setTurnAttr("mouth-right", "d", interpolateNumberString(turnBase.mouthRightD, turnTarget.mouthRightD, t));
      setTurnAttr("left-turn-blush-clip-path", "d", dynamicFacePath(t));
      setTurnAttr("face-layer", "transform", facePlaneTransform(t, 1));
      setTurnAttr("left-turn-blush-transform", "transform", facePlaneTransform(t, 1));
      setTurnAttr("head-tufts", "transform", tuftTransform(t));
      setTurnAttr("left-ear", "transform", earTransform({ x: 101, y: 73 }, { x: 97.5, y: 76.5 }, t));
      setTurnAttr("right-ear", "transform", earTransform({ x: 286, y: 73 }, { x: 286, y: 73 }, t));
      const rightEarGrow = smoothRange(.12, 1, t);
      setTurnAttr("right-ear-outer", "r", fmt(34 + (37.4 - 34) * rightEarGrow));
      setTurnAttr("right-ear-inner", "r", fmt(18 + (19.8 - 18) * rightEarGrow));
      setTurnAttr("left-eye", "transform", centeredTransform({ x: 138, y: 157 }, { x: 136, y: 157 }, t, { x: 0.97, y: 1 }));
      setTurnAttr("right-eye", "transform", centeredTransform({ x: 237, y: 157 }, { x: 237, y: 157 }, t));
      setTurnAttr("left-blush", "transform", centeredTransform({ x: 92, y: 185 }, { x: 98.5, y: 185 }, t));
      setTurnAttr("right-blush", "transform", centeredTransform({ x: 281, y: 185 }, { x: 306, y: 205.5 }, t, { x: 1.09, y: 1.1 }));
    }

    function render() {
      applyStageTheme();
      if (!svg) return;
      const pose = currentPose();
      clearNotificationLayers();
      resetBaseTransforms();
      applyLeftTurn(pose.headTurn || 0);
      applyOriginalHands();
      applyBodyPose(pose);
      applyBreathPose(pose);
      applyHeadPose(pose);
      applyBrowPose(pose);
      applyMouthPose(pose);
      applyFeetPose(pose);
      applyFootShapes(pose);
      applyDim();

      const rootGroup = svg.querySelector("#hamster-flat-master-v11") || svg;
      const headLayer = svg.querySelector("#notification-head-pose-layer") || svg.querySelector("#head-layer");
      const bodyLayer = svg.querySelector("#body-layer");
      const tieLayer = svg.querySelector("#tie");
      const handLayer = el("g", { id: "notification-original-hand-layer", "data-layer": "notification-original-noodle-hands" });
      const objectLayer = el("g", { id: "notification-object-layer", "data-layer": "notification-envelope" });
      const guideLayer = el("g", { id: "notification-guide-layer", "data-layer": "notification-guides" });

      drawIdleBackHands(rootGroup, bodyLayer, pose);
      if (bodyLayer) rootGroup.insertBefore(handLayer, bodyLayer);
      else if (headLayer) rootGroup.insertBefore(handLayer, headLayer);
      else if (tieLayer) rootGroup.insertBefore(handLayer, tieLayer.nextSibling);
      else rootGroup.appendChild(handLayer);
      handLayer.setAttribute("opacity", fmt(pose.frontHandOpacity ?? 1));
      rootGroup.appendChild(objectLayer);
      rootGroup.appendChild(guideLayer);

      markers = {};
      if ((pose.frontHandOpacity ?? 1) > .01) {
        ["left", "right"].forEach((side) => {
          const data = buildOriginalHandData(side, pose);
          markers[side] = data;
          drawRaisingNoodleHand(handLayer, side, pose);
          if (state.showGuides && (pose.frontHandOpacity ?? 1) > .18) drawOriginalHandGuides(guideLayer, side, data);
        });
      }
      const envelopeOpacity = pose.envelopeOpacity ?? 1;
      if (state.showEnvelope && envelopeOpacity > .01) drawEnvelope(objectLayer, pose, envelopeOpacity, "notification-envelope");
      const trailOpacity = pose.trailOpacity ?? 1;
      if (state.showTrail && trailOpacity > .01) drawEnvelopeTrail(objectLayer, pose, trailOpacity);
      const mark = notificationExclamationState(state.progress);
      if (mark.opacity > .01) drawNotificationExclamation(objectLayer, mark);
      if (state.showGuides) {
        drawHeadAxis(guideLayer, pose);
        drawFootContacts(guideLayer, pose);
      }
      svg.setAttribute("data-progress", fmt(state.progress));
      svg.setAttribute("data-stage", stageForProgress(state.progress).id);
    }

    function currentPose() {
      const progress = clamp(state.progress, 0, 100);
      const idle = idlePose();
      const look = lookPose();
      const peak = startPeakPose();
      let pose = idle;
      if (progress < ACTION.idleEnd) {
        pose = idle;
      } else if (progress < ACTION.lookEnd) {
        const t = easeOutQuart(range01(ACTION.idleEnd, ACTION.lookEnd, progress));
        pose = mixPose(idle, look, t);
        pose.browFocus = browFocusIn(progress);
        pose.trailOpacity = smoothRange(ACTION.idleEnd, ACTION.lookEnd, progress);
      } else if (progress < ACTION.catchPeak) {
        const raw = range01(ACTION.lookEnd, ACTION.reachPeak, progress);
        const raiseT = easeOutQuart(raw);
        pose = mixPose(look, peak, raiseT);
        pose.raiseT = raiseT;
        pose.frontHandOpacity = 1;
        pose.idleBackOpacity = 0;
        pose.mouthOpen = progress < ACTION.mouthPeak ? smoothRange(ACTION.mouthStart, ACTION.mouthPeak, progress) : 1;
        pose.browFocus = browFocusIn(progress);
        pose.breath = .18 * smoothRange(ACTION.mouthStart, ACTION.catchPeak, progress);
        pose.trailOpacity = 1;
      } else if (progress < ACTION.settled) {
        const t = smoothRange(ACTION.catchPeak, ACTION.settled, progress);
        pose = mixPose(peak, { ...FINAL, headTurn: 0, motionE: 0 }, t);
        pose.raiseT = 1;
        pose.frontHandOpacity = 1;
        pose.idleBackOpacity = 0;
        pose.mouthOpen = 1 - smoothRange(ACTION.catchPeak, 59, progress);
        pose.browFocus = 1;
        pose.breath = .18 + .42 * Math.sin(Math.PI * t);
        pose.trailOpacity = 1 - smoothRange(ACTION.catchPeak + 2, ACTION.settled, progress);
      } else if (progress < ACTION.waveEnd) {
        pose = wavePose(smoothRange(ACTION.settled, ACTION.waveEnd, progress));
      } else {
        pose = retractPose(smoothRange(ACTION.waveEnd, ACTION.returnEnd, progress));
      }
      pose.stage = stageForProgress(progress).id;
      return pose;
    }

    function idlePose() {
      return {
        headPivotX: 187, headPivotY: 228, headRotate: 0, headLift: 0, headScaleY: 1,
        headTurn: 0,
        bodyX: 0, bodyY: 0, bodyRotate: 0,
        leftFootX: 0, leftFootY: 0, leftFootRotate: 0,
        rightFootX: 0, rightFootY: 0, rightFootRotate: 0,
        leftHandX: 0, leftHandY: 0, leftHandRotate: 0, leftHandScaleX: 1, leftHandScaleY: 1.2,
        rightHandX: 0, rightHandY: 0, rightHandRotate: 0, rightHandScaleX: 1, rightHandScaleY: 1.2,
        envelopeX: state.mailStartX, envelopeY: state.mailStartY, envelopeW: FINAL.envelopeW, envelopeH: FINAL.envelopeH, envelopeRotate: -18,
        motionE: 0,
        raiseT: null,
        frontHandOpacity: 0,
        idleBackOpacity: 1,
        mouthOpen: 0,
        browFocus: 0,
        breath: 0,
        envelopeOpacity: 1,
        trailOpacity: 0
      };
    }

    function lookPose() {
      return {
        ...idlePose(),
        headTurn: 1,
        envelopeX: state.mailLookX,
        envelopeY: state.mailLookY,
        envelopeRotate: -29,
        trailOpacity: 1
      };
    }

    function startPeakPose() {
      const e = 1;
      const reachDir = -1;
      const pose = { ...FINAL, headTurn: 1, motionE: e, raiseT: 1, frontHandOpacity: 1, idleBackOpacity: 0, mouthOpen: 1, browFocus: 1, breath: .18, envelopeOpacity: 1, trailOpacity: 1 };
      pose.bodyX += reachDir * state.reachShift * e;
      pose.bodyY -= state.reachRise * e;
      pose.bodyRotate += reachDir * state.reachLean * e;
      pose.headLift -= state.headExtraLift * e;
      pose.headRotate += 1.5 * e;
      pose.leftHandX += state.catchHandX * e;
      pose.leftHandY += state.catchHandY * e;
      pose.leftHandRotate += state.catchHandRotate * e;
      pose.rightHandX += state.balanceHandX * e;
      pose.rightHandY += state.balanceHandY * e;
      pose.rightHandRotate += state.balanceHandRotate * e;
      pose.envelopeX += state.mailApproachX * e;
      pose.envelopeY += state.mailApproachY * e;
      pose.envelopeRotate -= 3 * e;
      pose.leftFootX += state.startLeftFootX * e;
      pose.leftFootY += state.startLeftFootY * e;
      pose.leftFootRotate += state.startLeftFootRotate * e;
      pose.rightFootX += state.startRightFootX * e;
      pose.rightFootY += state.startRightFootY * e;
      pose.rightFootRotate += state.startRightFootRotate * e;
      return pose;
    }

    function wavePose(e) {
      const pose = { ...FINAL, headTurn: 0, motionE: 0, raiseT: 1, frontHandOpacity: 1, idleBackOpacity: 0, envelopeOpacity: 1, trailOpacity: 0 };
      const fade = Math.sin(e * Math.PI);
      const wave = Math.sin(e * Math.PI * 6) * fade;
      const inhale = .35 + .65 * (0.5 - 0.5 * Math.cos(e * Math.PI * 6));
      pose.leftHandRotate += state.waveAngle * wave;
      pose.leftHandY -= state.waveLift * Math.max(0, wave) + state.waveLift * .28 * fade;
      pose.rightHandRotate -= state.waveBalance * .62 * wave;
      pose.rightHandY += state.waveBalance * .22 * wave;
      pose.rightHandX += state.waveBalance * .18 * wave;
      pose.bodyRotate += state.waveBody * .9 * wave;
      pose.bodyX += state.waveBody * .9 * wave;
      pose.headRotate += state.waveBody * .55 * wave;
      pose.headLift -= state.waveBody * .8 * inhale * fade;
      pose.mouthOpen = 0;
      pose.browFocus = 1;
      pose.breath = clamp(state.waveBody * inhale * fade, 0, 1);
      const finalTip = transformHandPoint("left", HAND_AXES.left.tip, FINAL);
      const currentTip = transformHandPoint("left", HAND_AXES.left.tip, pose);
      pose.envelopeX += currentTip.x - finalTip.x;
      pose.envelopeY += currentTip.y - finalTip.y;
      pose.envelopeRotate += pose.leftHandRotate - FINAL.leftHandRotate;
      return pose;
    }

    function retractPose(e) {
      const from = wavePose(1);
      const idle = idlePose();
      const t = smooth(e);
      const pose = mixPose(from, idle, t);
      pose.retractT = t;
      pose.raiseT = null;
      pose.frontHandOpacity = 1 - smoothRange(.82, 1, e);
      pose.idleBackOpacity = smoothRange(.58, 1, e);
      pose.envelopeOpacity = 1 - smoothRange(.08, .62, e);
      pose.trailOpacity = 0;
      pose.mouthOpen = from.mouthOpen * (1 - t);
      pose.breath = from.breath * (1 - t);
      return pose;
    }

    function mixPose(a, b, t) {
      const out = { ...a };
      Object.keys(b).forEach((key) => {
        if (typeof a[key] === "number" && typeof b[key] === "number") {
          out[key] = a[key] + (b[key] - a[key]) * t;
        } else {
          out[key] = t < .5 ? a[key] : b[key];
        }
      });
      return out;
    }

    function stageForProgress(progress) {
      if (Math.abs(progress - ACTION.catchPeak) < 0.001) return { id: "start-peak", label: "截获峰值" };
      if (Math.abs(progress - ACTION.settled) < 0.001) return { id: "settled-catch", label: "已接住" };
      return TIMELINE.find((item) => progress >= item.start && progress < item.end) || TIMELINE[TIMELINE.length - 1];
    }

    function mixPoint(a, b, t) {
      return {
        x: a.x + (b.x - a.x) * t,
        y: a.y + (b.y - a.y) * t
      };
    }

    function smooth(value) {
      return value * value * (3 - 2 * value);
    }

    function range01(start, end, value) {
      return clamp((value - start) / (end - start), 0, 1);
    }

    function smoothRange(start, end, value) {
      return smooth(range01(start, end, value));
    }

    function easeOutCubic(value) {
      const t = clamp(value, 0, 1) - 1;
      return t * t * t + 1;
    }

    function easeOutQuart(value) {
      const t = clamp(value, 0, 1) - 1;
      return 1 - t * t * t * t;
    }

    function browFocusIn(progress) {
      return easeOutCubic(range01(ACTION.browStart, ACTION.catchPeak, progress));
    }

    function clearNotificationLayers() {
      [
        "#notification-original-hand-layer",
        "#notification-idle-back-hand-layer",
        "#notification-object-layer",
        "#notification-guide-layer"
      ].forEach((selector) => svg.querySelector(selector)?.remove());
    }

    function resetBaseTransforms() {
      Object.entries(baseTransform).forEach(([id, transform]) => {
        const node = svg.querySelector(`#${id}`);
        if (!node) return;
        if (transform) node.setAttribute("transform", transform);
        else node.removeAttribute("transform");
        node.style.transformBox = "view-box";
        node.style.transformOrigin = "0px 0px";
      });
      Object.entries(basePath).forEach(([id, d]) => {
        const node = svg.querySelector(`#${id}`);
        if (node) node.setAttribute("d", d);
      });
    }

    function applyOriginalHands() {
      const originalHands = svg.querySelector("#hands-layer");
      if (!originalHands) return;
      originalHands.style.display = state.showOriginalHands ? "" : "none";
      originalHands.setAttribute("opacity", state.showOriginalHands ? ".22" : "1");
    }

    function drawIdleBackHands(rootGroup, bodyLayer, pose) {
      const opacity = pose.idleBackOpacity ?? 0;
      if (!idleSourceSvg || opacity <= .01) return;
      const backHands = idleSourceSvg.querySelector("#arm-back-split-layer");
      const handShadow = idleSourceSvg.querySelector("#body-cast-shadow-on-hand-layer");
      if (!backHands) return;
      const wrapper = el("g", {
        id: "notification-idle-back-hand-layer",
        "data-layer": "notification-idle-confirmed-back-hands",
        opacity: fmt(opacity),
        transform: bodyTransform(pose)
      });
      wrapper.appendChild(backHands.cloneNode(true));
      if (handShadow) wrapper.appendChild(handShadow.cloneNode(true));
      if (bodyLayer) rootGroup.insertBefore(wrapper, bodyLayer);
      else rootGroup.appendChild(wrapper);
    }

    function drawRaisingNoodleHand(layer, side, pose) {
      const curve = buildRaisedHandCurve(side, pose);
      if (!curve) return;
      const group = el("g", {
        id: `notification-${side}-real-raise-hand`,
        "data-role": `notification-${side}-real-noodle-hand-raise`
      });
      HAND_IDS[side].forEach((id) => {
        const d = baseHandPath[id];
        const source = svg.querySelector(`#${id}`);
        if (!d || !source) return;
        group.appendChild(el("path", {
          d: denseWarpHandPath(d, (point) => bendHandPoint(side, curve, point)),
          fill: source.getAttribute("fill") || "#fff8f0"
        }));
      });
      layer.appendChild(group);
    }

    function buildRaisedHandCurve(side, pose) {
      if ((pose.frontHandOpacity ?? 0) <= .01) return null;
      if (pose.retractT != null) {
        const retractT = clamp(pose.retractT, 0, 1);
        const front = transformedHandControlPoints(side, pose);
        const back = backHandControlPoints(side);
        const points = front.map((point, index) => mixPoint(point, back[index], retractT));
        const sourceThickness = pose[`${side}HandScaleY`] || 1;
        return buildHandCurve(points, 1 + (sourceThickness - 1) * (1 - retractT));
      }
      const raiseT = pose.raiseT == null ? 1 : clamp(pose.raiseT, 0, 1);
      if (raiseT < 1) {
        const peak = startPeakPose();
        const back = backHandControlPoints(side);
        const front = transformedHandControlPoints(side, peak);
        const points = back.map((point, index) => mixPoint(point, front[index], raiseT));
        return buildHandCurve(points, 1 + ((peak[`${side}HandScaleY`] || 1) - 1) * raiseT);
      }
      return buildHandCurve(transformedHandControlPoints(side, pose), pose[`${side}HandScaleY`] || 1);
    }

    function backHandControlPoints(side) {
      if (side === "left") {
        return [
          { x: 118, y: 257 },
          { x: 98, y: 242 },
          { x: 71, y: 267 },
          { x: 55, y: 308 },
          { x: 66, y: 342 }
        ];
      }
      return [
        { x: 256, y: 257 },
        { x: 276, y: 242 },
        { x: 303, y: 267 },
        { x: 319, y: 308 },
        { x: 308, y: 342 }
      ];
    }

    function transformedHandControlPoints(side, pose) {
      return [0, .18, .4, .72, 1].map((stop) => transformHandPoint(side, sourceHandCenterPoint(side, stop), pose));
    }

    function sourceHandCenterPoint(side, stop) {
      const axis = HAND_AXES[side];
      return {
        x: axis.root.x + (axis.tip.x - axis.root.x) * stop,
        y: axis.root.y + (axis.tip.y - axis.root.y) * stop
      };
    }

    function buildHandCurve(points, thickness) {
      const samples = [];
      const stepsPerSegment = 24;
      let length = 0;
      for (let segment = 0; segment < points.length - 1; segment += 1) {
        const p0 = points[Math.max(0, segment - 1)];
        const p1 = points[segment];
        const p2 = points[segment + 1];
        const p3 = points[Math.min(points.length - 1, segment + 2)];
        for (let step = 0; step <= stepsPerSegment; step += 1) {
          if (segment > 0 && step === 0) continue;
          const t = step / stepsPerSegment;
          const point = catmullRom(p0, p1, p2, p3, t);
          const tangent = normalize(catmullRomTangent(p0, p1, p2, p3, t));
          if (samples.length) {
            const previous = samples[samples.length - 1];
            length += Math.hypot(point.x - previous.x, point.y - previous.y);
          }
          samples.push({ ...point, ux: tangent.x, uy: tangent.y, along: length });
        }
      }
      return { points, samples, length, thickness };
    }

    function sampleHandCurve(curve, fraction) {
      if (!curve.samples.length) return { x: 0, y: 0, ux: 1, uy: 0, along: 0 };
      const target = clamp(fraction, 0, 1) * curve.length;
      let previous = curve.samples[0];
      for (let i = 1; i < curve.samples.length; i += 1) {
        const current = curve.samples[i];
        if (current.along >= target) {
          const span = current.along - previous.along || 1;
          const t = (target - previous.along) / span;
          return {
            x: previous.x + (current.x - previous.x) * t,
            y: previous.y + (current.y - previous.y) * t,
            ux: previous.ux + (current.ux - previous.ux) * t,
            uy: previous.uy + (current.uy - previous.uy) * t,
            along: target
          };
        }
        previous = current;
      }
      return curve.samples[curve.samples.length - 1];
    }

    function bendHandPoint(side, curve, point) {
      const axis = HAND_AXES[side];
      const sourceLen = Math.hypot(axis.tip.x - axis.root.x, axis.tip.y - axis.root.y) || 1;
      const sourceAlong = side === "left"
        ? (axis.root.x - point.x) / sourceLen
        : (point.x - axis.root.x) / sourceLen;
      const sample = sampleHandCurve(curve, sourceAlong);
      const tangent = normalize({ x: sample.ux, y: sample.uy });
      const normal = side === "left"
        ? normalize({ x: tangent.y, y: -tangent.x })
        : normalize({ x: -tangent.y, y: tangent.x });
      const offset = (point.y - axis.root.y) * curve.thickness;
      return {
        x: sample.x + normal.x * offset,
        y: sample.y + normal.y * offset
      };
    }

    function denseWarpHandPath(d, fn) {
      const tokens = d.match(/[MLCQZmlcqz]|-?\d*\.?\d+(?:e-?\d+)?/g) || [];
      const out = [];
      let i = 0;
      let cmd = "";
      let current = { x: 0, y: 0 };
      let start = { x: 0, y: 0 };
      let open = false;

      const readPoint = () => ({ x: Number(tokens[i++]), y: Number(tokens[i++]) });
      const pushPoint = (point) => {
        const bent = fn(point);
        if (!open) {
          out.push(`M ${fmt(bent.x)} ${fmt(bent.y)}`);
          open = true;
        } else {
          out.push(`L ${fmt(bent.x)} ${fmt(bent.y)}`);
        }
      };
      const pushLine = (from, to, steps = 6) => {
        for (let step = 1; step <= steps; step += 1) {
          const t = step / steps;
          pushPoint({
            x: from.x + (to.x - from.x) * t,
            y: from.y + (to.y - from.y) * t
          });
        }
      };

      while (i < tokens.length) {
        if (/[A-Za-z]/.test(tokens[i])) cmd = tokens[i++];
        if (cmd === "M") {
          current = readPoint();
          start = current;
          pushPoint(current);
        } else if (cmd === "L") {
          const next = readPoint();
          pushLine(current, next, 8);
          current = next;
        } else if (cmd === "C") {
          const c1 = readPoint();
          const c2 = readPoint();
          const next = readPoint();
          for (let step = 1; step <= 12; step += 1) {
            pushPoint(cubicBezier(current, c1, c2, next, step / 12));
          }
          current = next;
        } else if (cmd === "Q") {
          const c = readPoint();
          const next = readPoint();
          for (let step = 1; step <= 10; step += 1) {
            const t = step / 10;
            const mt = 1 - t;
            pushPoint({
              x: current.x * mt * mt + 2 * c.x * mt * t + next.x * t * t,
              y: current.y * mt * mt + 2 * c.y * mt * t + next.y * t * t
            });
          }
          current = next;
        } else if (cmd === "Z" || cmd === "z") {
          pushLine(current, start, 8);
          out.push("Z");
          open = false;
          current = start;
        } else {
          break;
        }
      }
      return out.join(" ");
    }

    function cubicBezier(p0, p1, p2, p3, t) {
      const mt = 1 - t;
      const mt2 = mt * mt;
      const mt3 = mt2 * mt;
      const t2 = t * t;
      const t3 = t2 * t;
      return {
        x: p0.x * mt3 + 3 * p1.x * mt2 * t + 3 * p2.x * mt * t2 + p3.x * t3,
        y: p0.y * mt3 + 3 * p1.y * mt2 * t + 3 * p2.y * mt * t2 + p3.y * t3
      };
    }

    function catmullRom(p0, p1, p2, p3, t) {
      const t2 = t * t;
      const t3 = t2 * t;
      return {
        x: .5 * ((2 * p1.x) + (-p0.x + p2.x) * t + (2 * p0.x - 5 * p1.x + 4 * p2.x - p3.x) * t2 + (-p0.x + 3 * p1.x - 3 * p2.x + p3.x) * t3),
        y: .5 * ((2 * p1.y) + (-p0.y + p2.y) * t + (2 * p0.y - 5 * p1.y + 4 * p2.y - p3.y) * t2 + (-p0.y + 3 * p1.y - 3 * p2.y + p3.y) * t3)
      };
    }

    function catmullRomTangent(p0, p1, p2, p3, t) {
      const t2 = t * t;
      return {
        x: .5 * ((-p0.x + p2.x) + 2 * (2 * p0.x - 5 * p1.x + 4 * p2.x - p3.x) * t + 3 * (-p0.x + 3 * p1.x - 3 * p2.x + p3.x) * t2),
        y: .5 * ((-p0.y + p2.y) + 2 * (2 * p0.y - 5 * p1.y + 4 * p2.y - p3.y) * t + 3 * (-p0.y + 3 * p1.y - 3 * p2.y + p3.y) * t2)
      };
    }

    function normalize(vector) {
      const len = Math.hypot(vector.x, vector.y) || 1;
      return { x: vector.x / len, y: vector.y / len };
    }

    function applyBodyPose(pose) {
      const T = bodyTransform(pose);
      ["body-layer", "tail"].forEach((id) => {
        const node = svg.querySelector(`#${id}`);
        if (!node) return;
        node.setAttribute("transform", `${T} ${baseTransform[id] || ""}`.trim());
      });
      const tie = svg.querySelector("#tie");
      if (tie) {
        const base = baseTransform.tie || "";
        tie.setAttribute("transform", `${T} ${base}`.trim());
      }
    }

    function bodyTransform(pose) {
      const pivot = { x: 187 + pose.bodyX, y: 354 + pose.bodyY };
      return [
        `translate(${fmt(pose.bodyX)} ${fmt(pose.bodyY)})`,
        `rotate(${fmt(pose.bodyRotate)} ${fmt(pivot.x)} ${fmt(pivot.y)})`
      ].join(" ");
    }

    function applyBreathPose(pose) {
      const b = clamp(pose.breath || 0, 0, 1);
      const body = svg.querySelector("#body-belly-fill");
      if (body) body.setAttribute("d", b > .001 ? bodyBreathPath(b) : basePath["body-belly-fill"]);
      applyTieMotion(pose, b);
    }

    function bodyBreathPath(b) {
      const expand = BREATH.bodyExpand * b;
      const topLift = BREATH.bodyTopLift * b;
      const bottomDrop = BREATH.bodyBottomDrop * b;
      const leftX = 60 - expand;
      const rightX = 314 + expand;
      const topY = 200 - topLift;
      const bottomY = 412 + bottomDrop * .35;
      const lowerCtrlY = 380 + bottomDrop;
      return [
        `M187 ${fmt(topY)}`,
        `C ${fmt(113 - expand * .58)} ${fmt(topY)} ${fmt(leftX)} 251 ${fmt(leftX)} 322`,
        `C ${fmt(leftX)} ${fmt(lowerCtrlY)} 101 ${fmt(bottomY)} 187 ${fmt(bottomY)}`,
        `C 273 ${fmt(bottomY)} ${fmt(rightX)} ${fmt(lowerCtrlY)} ${fmt(rightX)} 322`,
        `C ${fmt(rightX)} 251 ${fmt(261 + expand * .58)} ${fmt(topY)} 187 ${fmt(topY)}Z`
      ].join(" ");
    }

    function applyTieMotion(pose, b) {
      const response = tieResponseMotion(pose);
      const knotDx = BREATH.tieKnotShift * b + response.knotDx;
      const knotDy = response.knotDy;
      const swing = BREATH.tieSwing * b + response.swing;
      const knotMove = Math.abs(knotDx) < 1e-6 && Math.abs(knotDy) < 1e-6
        ? ""
        : `translate(${fmt(knotDx)} ${fmt(knotDy)})`;
      const bladeSwing = Math.abs(knotDx) < 1e-6 && Math.abs(knotDy) < 1e-6 && Math.abs(swing) < 1e-6
        ? ""
        : `${knotMove} rotate(${fmt(swing)} 34 14)`.trim();
      ["tie-knot", "tie-knot-highlight"].forEach((id) => setElementTransform(id, knotMove));
      ["tie-shadow", "tie-blade", "tie-center-fold", "tie-left-fold"].forEach((id) => setElementTransform(id, bladeSwing));
    }

    function tieResponseMotion(pose) {
      const progress = clamp(state.progress, 0, 100);
      const catchImpulse = pulseRange(TIE_RESPONSE.catchStart, TIE_RESPONSE.catchPeak, TIE_RESPONSE.catchSettle, progress);
      const waveT = range01(ACTION.settled, ACTION.waveEnd, progress);
      const waveFade = Math.sin(waveT * Math.PI);
      const waveBeat = waveFade > 0 ? Math.sin(waveT * Math.PI * 6) * waveFade : 0;
      return {
        knotDx: TIE_RESPONSE.catchKnotDx * catchImpulse + TIE_RESPONSE.waveKnotDx * waveBeat,
        knotDy: TIE_RESPONSE.catchKnotDy * catchImpulse,
        swing:
          TIE_RESPONSE.catchSwing * catchImpulse +
          TIE_RESPONSE.waveSwing * waveBeat +
          TIE_RESPONSE.bodyLag * (pose.bodyRotate || 0)
      };
    }

    function pulseRange(start, peak, end, value) {
      if (value <= start || value >= end) return 0;
      if (value <= peak) return smoothRange(start, peak, value);
      return 1 - smoothRange(peak, end, value);
    }

    function setElementTransform(id, extraTransform) {
      const node = svg.querySelector(`#${id}`);
      if (!node) return;
      const transform = [baseTransform[id] || "", extraTransform].filter(Boolean).join(" ");
      if (transform) node.setAttribute("transform", transform);
      else node.removeAttribute("transform");
    }

    function applyHeadPose(pose) {
      const head = svg.querySelector("#notification-head-pose-layer");
      if (!head) return;
      const p = { x: pose.headPivotX, y: pose.headPivotY };
      const transform = [
        `translate(0 ${fmt(pose.headLift)})`,
        `rotate(${fmt(pose.headRotate)} ${fmt(p.x)} ${fmt(p.y)})`,
        `translate(${fmt(p.x)} ${fmt(p.y)}) scale(1 ${fmt(pose.headScaleY)}) translate(${fmt(-p.x)} ${fmt(-p.y)})`
      ].join(" ");
      head.setAttribute("transform", transform);
    }

    function applyBrowPose(pose) {
      const focus = smooth(clamp(pose.browFocus || 0, 0, 1));
      setTurnAttr("left-brow", "d", interpolateNumberString(BROW_POSES.leftNeutral, BROW_POSES.leftFocus, focus));
      setTurnAttr("right-brow", "d", interpolateNumberString(BROW_POSES.rightNeutral, BROW_POSES.rightFocus, focus));
    }

    function applyMouthPose(pose) {
      const open = clamp(pose.mouthOpen || 0, 0, 1);
      const interior = svg.querySelector("#mouth-interior-clipped");
      const clipPath = svg.querySelector("#mouth-opening-clip-path");
      const cavity = svg.querySelector("#mouth-cavity-fill");
      const lower = svg.querySelector("#mouth-lower-cavity-fill");
      if (!interior || !clipPath || !cavity || !lower) return;
      if (open <= .01) {
        interior.style.display = "none";
        return;
      }
      interior.style.display = "";
      interior.setAttribute("opacity", fmt(.72 + .28 * open));
      clipPath.setAttribute("d", mouthOpeningClipD(open));
      cavity.setAttribute("d", mouthCavityD(open));
      lower.setAttribute("d", mouthLowerCavityD(open));
    }

    function mouthOpeningClipD(open) {
      const progress = HAPPY_MOUTH.maxProgress * clamp(open, 0, 1);
      const p = progress / 100;
      const cx = HAPPY_MOUTH.cx;
      const sideY = HAPPY_MOUTH.sideY;
      if (p <= .01) {
        return `M ${fmt(cx - .5)} ${fmt(sideY)} C ${fmt(cx - .5)} ${fmt(sideY + .3)} ${fmt(cx + .5)} ${fmt(sideY + .3)} ${fmt(cx + .5)} ${fmt(sideY)} C ${fmt(cx + .5)} ${fmt(sideY - .3)} ${fmt(cx - .5)} ${fmt(sideY - .3)} ${fmt(cx - .5)} ${fmt(sideY)} Z`;
      }
      const dx = cx - 187;
      const topYShift = (sideY - 199) * .18;
      const tx = (x) => x + dx;
      const ty = (y) => y + topYShift;
      const bd = Math.max(.15, HAPPY_MOUTH.bottomDrop * p);
      const bottomY = sideY + bd;
      const bottomW = Math.max(6, HAPPY_MOUTH.halfW * p);
      return [
        `M ${fmt(tx(163))} ${fmt(ty(192))}`,
        `C ${fmt(tx(163))} ${fmt(ty(195))} ${fmt(tx(166))} ${fmt(ty(198))} ${fmt(tx(171))} ${fmt(ty(198))}`,
        `C ${fmt(tx(180))} ${fmt(ty(198))} ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(187))} ${fmt(ty(177))}`,
        `C ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(194))} ${fmt(ty(198))} ${fmt(tx(203))} ${fmt(ty(198))}`,
        `C ${fmt(tx(208))} ${fmt(ty(198))} ${fmt(tx(211))} ${fmt(ty(195))} ${fmt(tx(211))} ${fmt(ty(192))}`,
        `C ${fmt(tx(211))} ${fmt(bottomY - bd * .15)} ${fmt(cx + bottomW)} ${fmt(bottomY)} ${fmt(cx)} ${fmt(bottomY)}`,
        `C ${fmt(cx - bottomW)} ${fmt(bottomY)} ${fmt(tx(163))} ${fmt(bottomY - bd * .15)} ${fmt(tx(163))} ${fmt(ty(192))} Z`
      ].join(" ");
    }

    function mouthCavityD(open) {
      const cx = HAPPY_MOUTH.cx;
      const cy = HAPPY_MOUTH.cavityY;
      const w = HAPPY_MOUTH.cavityW * (.72 + .28 * open);
      const h = HAPPY_MOUTH.cavityH * (.68 + .32 * open);
      return [
        `M ${fmt(cx - w)} ${fmt(cy)}`,
        `C ${fmt(cx - w)} ${fmt(cy - h * .55)} ${fmt(cx + w)} ${fmt(cy - h * .55)} ${fmt(cx + w)} ${fmt(cy)}`,
        `C ${fmt(cx + w)} ${fmt(cy + h * .66)} ${fmt(cx - w)} ${fmt(cy + h * .66)} ${fmt(cx - w)} ${fmt(cy)} Z`
      ].join(" ");
    }

    function mouthLowerCavityD(open) {
      const progress = HAPPY_MOUTH.maxProgress * clamp(open, 0, 1);
      const tp = clamp((progress - 18) / 82, 0, 1);
      const cx = HAPPY_MOUTH.cx;
      const y = HAPPY_MOUTH.lowerCavityY;
      const lcw = Math.max(.1, HAPPY_MOUTH.lowerCavityW * tp);
      const lch = Math.max(.1, HAPPY_MOUTH.lowerCavityH * tp);
      const tail = 46 + HAPPY_MOUTH.bottomDrop;
      return [
        `M ${fmt(cx - lcw)} ${fmt(y)}`,
        `C ${fmt(cx - lcw * .82)} ${fmt(y - lch)} ${fmt(cx + lcw * .82)} ${fmt(y - lch)} ${fmt(cx + lcw)} ${fmt(y)}`,
        `L ${fmt(cx + lcw * 1.28)} ${fmt(y + tail)}`,
        `L ${fmt(cx - lcw * 1.28)} ${fmt(y + tail)} Z`
      ].join(" ");
    }

    function applyFeetPose(pose) {
      applyFoot("left", pose.leftFootX, pose.leftFootY, pose.leftFootRotate);
      applyFoot("right", pose.rightFootX, pose.rightFootY, pose.rightFootRotate);
    }

    function applyFootShapes(pose) {
      const e = pose.motionE || 0;
      if (e <= 0) return;
      const support = state.tiptoeSide;
      const fill = svg.querySelector(`#${support}-foot-fill`);
      const d = basePath[`${support}-foot-fill`];
      if (!fill || !d) return;
      fill.setAttribute("d", tiptoeFootPath(support, d, e));
    }

    function applyFoot(side, tx, ty, rotate) {
      const foot = svg.querySelector(`#${side}-foot`);
      if (!foot) return;
      const o = FOOT_ORIGINS[side];
      foot.style.transformBox = "view-box";
      foot.style.transformOrigin = "0px 0px";
      foot.setAttribute("transform", `translate(${fmt(tx)} ${fmt(ty)}) rotate(${fmt(rotate)} ${fmt(o.x)} ${fmt(o.y)})`);
    }

    function tiptoeFootPath(side, d, e) {
      const shape = FOOT_SHAPE[side];
      const narrow = 1 - (1 - state.tiptoeNarrow) * e;
      const lift = state.tiptoeTopLift * e;
      return transformPathXY(d, (p) => {
        const h = clamp((shape.groundY - p.y) / (shape.groundY - shape.topY), 0, 1.25);
        return {
          x: shape.centerX + (p.x - shape.centerX) * (1 - (1 - narrow) * h),
          y: p.y - lift * h
        };
      });
    }

    function transformPathXY(d, fn) {
      const tokens = d.match(/[MLCQZmlcqz]|-?\d*\.?\d+(?:e-?\d+)?/g) || [];
      let out = "";
      let pending = [];
      for (const token of tokens) {
        if (/[A-Za-z]/.test(token)) {
          out += token;
          pending = [];
        } else {
          pending.push(parseFloat(token));
          if (pending.length === 2) {
            const p = fn({ x: pending[0], y: pending[1] });
            out += `${fmt(p.x)} ${fmt(p.y)} `;
            pending = [];
          }
        }
      }
      return out.trim();
    }

    function applyDim() {
      for (const selector of ["#ears-layer", "#head-layer", "#head-tufts", "#face-layer", "#tie", "#tail"]) {
        const node = svg.querySelector(selector);
        if (node) node.setAttribute("opacity", state.dimFace ? ".38" : "1");
      }
      const sunglasses = svg.querySelector("#sunglasses");
      if (sunglasses) {
        sunglasses.style.display = "";
        sunglasses.removeAttribute("display");
        sunglasses.setAttribute("opacity", state.dimFace ? ".38" : "1");
      }
    }

    function buildOriginalHandData(side, pose) {
      const curve = buildRaisedHandCurve(side, pose);
      if (curve) {
        const root = sampleHandCurve(curve, 0);
        const tip = sampleHandCurve(curve, 1);
        const bones = HAND_BONE_STOPS.map(([label, stop]) => {
          if (stop < 0) {
            const shoulder = {
              x: root.x - root.ux * Math.abs(stop),
              y: root.y - root.uy * Math.abs(stop)
            };
            return [label, shoulder];
          }
          return [label, sampleHandCurve(curve, stop)];
        });
        return {
          side,
          transform: "dense-warped-real-raise",
          root,
          tip,
          bones
        };
      }
      const source = HAND_AXES[side];
      const sourceBones = buildSourceBones(side);
      return {
        side,
        transform: handTransform(side, pose),
        root: transformHandPoint(side, source.root, pose),
        tip: transformHandPoint(side, source.tip, pose),
        bones: sourceBones.map(([label, point]) => [label, transformHandPoint(side, point, pose)])
      };
    }

    function drawOriginalNoodleHand(layer, side, data) {
      const source = svg.querySelector(`#${side}-hand`);
      if (!source) return;
      const clone = source.cloneNode(true);
      prefixCloneIds(clone, `notification-${side}`);
      clone.setAttribute("id", `notification-${side}-original-noodle-hand`);
      clone.setAttribute("data-role", `notification-${side}-original-noodle-hand`);
      clone.setAttribute("transform", data.transform);
      clone.style.transformBox = "view-box";
      clone.style.transformOrigin = "0px 0px";
      layer.appendChild(clone);
    }

    function drawOriginalHandGuides(layer, side, data) {
      const color = side === "left" ? "#ad4938" : "#14776c";
      const group = el("g", { "data-role": `notification-${side}-hand-guides` });
      group.appendChild(el("path", {
        d: data.bones.map(([label, point], index) => `${index ? "L" : "M"} ${fmt(point.x)} ${fmt(point.y)}`).join(" "),
        fill: "none",
        stroke: color,
        "stroke-width": "2",
        "stroke-dasharray": "7 6",
        "stroke-linecap": "round",
        "stroke-linejoin": "round",
        opacity: ".62"
      }));
      data.bones.forEach(([label, point]) => {
        const isEnd = label === "S" || label === "T";
        group.appendChild(el("circle", {
          cx: fmt(point.x),
          cy: fmt(point.y),
          r: isEnd ? "6" : "5",
          fill: color,
          stroke: "#fffaf3",
          "stroke-width": "2",
          opacity: ".9"
        }));
        if (!state.showLabels) return;
        const text = el("text", {
          x: fmt(point.x),
          y: fmt(point.y + (label === "S" || label === "R" ? -16 : 21)),
          fill: color,
          "font-size": "12",
          "font-weight": "700",
          "text-anchor": "middle",
          "paint-order": "stroke",
          stroke: "#fffaf3",
          "stroke-width": "3"
        });
        text.textContent = `${side === "left" ? "L" : "R"}${label}`;
        group.appendChild(text);
      });
      layer.appendChild(group);
    }

    function buildSourceBones(side) {
      const axis = HAND_AXES[side];
      const outward = {
        x: axis.tip.x - axis.root.x,
        y: axis.tip.y - axis.root.y
      };
      const len = Math.hypot(outward.x, outward.y) || 1;
      const ux = outward.x / len;
      const uy = outward.y / len;
      return HAND_BONE_STOPS.map(([label, stop]) => {
        const along = stop < 0 ? stop : len * stop;
        return [label, {
          x: axis.root.x + ux * along,
          y: axis.root.y + uy * along
        }];
      });
    }

    function handTransform(side, pose) {
      const source = HAND_AXES[side];
      const tx = pose[`${side}HandX`];
      const ty = pose[`${side}HandY`];
      const rotate = pose[`${side}HandRotate`];
      const sx = pose[`${side}HandScaleX`];
      const sy = pose[`${side}HandScaleY`];
      const root = source.root;
      return [
        `translate(${fmt(tx)} ${fmt(ty)})`,
        `rotate(${fmt(rotate)} ${fmt(root.x)} ${fmt(root.y)})`,
        `translate(${fmt(root.x)} ${fmt(root.y)}) scale(${fmt(sx)} ${fmt(sy)}) translate(${fmt(-root.x)} ${fmt(-root.y)})`
      ].join(" ");
    }

    function transformHandPoint(side, point, pose) {
      const source = HAND_AXES[side];
      const root = source.root;
      const sx = pose[`${side}HandScaleX`];
      const sy = pose[`${side}HandScaleY`];
      const angle = pose[`${side}HandRotate`] * Math.PI / 180;
      const tx = pose[`${side}HandX`];
      const ty = pose[`${side}HandY`];
      const scaled = {
        x: root.x + (point.x - root.x) * sx,
        y: root.y + (point.y - root.y) * sy
      };
      const dx = scaled.x - root.x;
      const dy = scaled.y - root.y;
      return {
        x: root.x + dx * Math.cos(angle) - dy * Math.sin(angle) + tx,
        y: root.y + dx * Math.sin(angle) + dy * Math.cos(angle) + ty
      };
    }

    function prefixCloneIds(node, prefix) {
      if (node.id) node.id = `${prefix}-${node.id}`;
      node.querySelectorAll("[id]").forEach((child) => {
        child.id = `${prefix}-${child.id}`;
      });
    }

    function notificationExclamationState(progress) {
      if (progress < EXCLAMATION.start || progress > EXCLAMATION.end) {
        return { opacity: 0, scale: 0, pulse: 0, x: EXCLAMATION.x, y: EXCLAMATION.y, rotate: EXCLAMATION.rotate };
      }
      const inT = smoothRange(EXCLAMATION.start, EXCLAMATION.popEnd, progress);
      const outT = smoothRange(EXCLAMATION.holdEnd, EXCLAMATION.end, progress);
      const popT = clamp(range01(EXCLAMATION.start, EXCLAMATION.popEnd, progress), 0, 1);
      const popBounce = Math.sin(Math.PI * popT);
      const waveT = clamp(range01(ACTION.settled, ACTION.waveEnd, progress), 0, 1);
      const waveFade = smoothRange(ACTION.settled, ACTION.settled + 3, progress) * (1 - smoothRange(EXCLAMATION.holdEnd, EXCLAMATION.end, progress));
      const wavePulse = (0.5 - 0.5 * Math.cos(waveT * Math.PI * 6)) * waveFade;
      const waveWobble = Math.sin(waveT * Math.PI * 6) * waveFade;
      const baseOpacity = progress < EXCLAMATION.holdEnd ? inT : 1 - outT;
      const waveOpacity = 1 - .18 * waveFade + .18 * wavePulse;
      return {
        opacity: baseOpacity * waveOpacity,
        pulse: wavePulse,
        scale: EXCLAMATION.scale * (.7 + .3 * inT + .06 * popBounce + .045 * wavePulse - .07 * outT),
        x: EXCLAMATION.x,
        y: EXCLAMATION.y,
        rotate: EXCLAMATION.rotate - 8 * (1 - inT) + 1.2 * waveWobble + 5 * outT
      };
    }

    function drawNotificationExclamation(layer, mark) {
      const pulse = mark.pulse || 0;
      const stemTop = EXCLAMATION.stemTop;
      const stemBottom = EXCLAMATION.stemBottom;
      const stemHeight = Math.max(8, Math.abs(stemBottom - stemTop));
      const bend = clamp(stemHeight * .1, 2.2, 4.8);
      const stemMidA = stemTop + stemHeight * .34;
      const stemMidB = stemTop + stemHeight * .72;
      const stemWidth = EXCLAMATION.stemWidth;
      const outlineWidth = stemWidth + 6;
      const haloWidth = stemWidth + 12 + 3 * pulse;
      const dotY = EXCLAMATION.dotY;
      const dotR = EXCLAMATION.dotR;
      const haloOpacity = clamp(EXCLAMATION.haloOpacity * (1 + .75 * pulse), 0, .72);
      const highlightOpacity = clamp(.72 + .18 * pulse, 0, .92);
      const group = el("g", {
        id: "notification-exclamation-mark",
        "data-role": "notification-exclamation",
        transform: `translate(${fmt(mark.x)} ${fmt(mark.y)}) rotate(${fmt(mark.rotate)}) scale(${fmt(mark.scale)})`,
        opacity: fmt(mark.opacity)
      });
      const stemD = `M 0 ${fmt(stemTop)} C ${fmt(bend)} ${fmt(stemMidA)} ${fmt(bend * .7)} ${fmt(stemMidB)} 0 ${fmt(stemBottom)}`;
      group.appendChild(el("path", {
        d: stemD,
        fill: "none",
        stroke: EXCLAMATION.halo,
        "stroke-width": fmt(haloWidth),
        "stroke-linecap": "round",
        opacity: fmt(haloOpacity)
      }));
      group.appendChild(el("circle", {
        cx: "0",
        cy: fmt(dotY),
        r: fmt(dotR + 6 + 1.3 * pulse),
        fill: EXCLAMATION.halo,
        opacity: fmt(haloOpacity * .92)
      }));
      group.appendChild(el("path", {
        d: stemD,
        fill: "none",
        stroke: EXCLAMATION.stroke,
        "stroke-width": fmt(outlineWidth),
        "stroke-linecap": "round",
        "stroke-linejoin": "round"
      }));
      group.appendChild(el("path", {
        d: stemD,
        fill: "none",
        stroke: EXCLAMATION.fill,
        "stroke-width": fmt(stemWidth),
        "stroke-linecap": "round",
        "stroke-linejoin": "round"
      }));
      group.appendChild(el("path", {
        d: `M ${fmt(bend * .85)} ${fmt(stemTop + 5)} C ${fmt(bend + 1)} ${fmt(stemMidA)} ${fmt(bend * .75)} ${fmt(stemMidB - 2)} ${fmt(bend * .38)} ${fmt(stemBottom - 4)}`,
        fill: "none",
        stroke: EXCLAMATION.highlight,
        "stroke-width": fmt(Math.max(1.7, stemWidth * .3)),
        "stroke-linecap": "round",
        opacity: fmt(highlightOpacity)
      }));
      group.appendChild(el("circle", {
        cx: "0",
        cy: fmt(dotY),
        r: fmt(dotR + 2.6),
        fill: EXCLAMATION.stroke
      }));
      group.appendChild(el("circle", {
        cx: "0",
        cy: fmt(dotY),
        r: fmt(dotR),
        fill: EXCLAMATION.fill
      }));
      group.appendChild(el("circle", {
        cx: fmt(-dotR * .3),
        cy: fmt(dotY - dotR * .38),
        r: fmt(Math.max(1, dotR * .25)),
        fill: EXCLAMATION.highlight,
        opacity: fmt(clamp(.8 + .12 * pulse, 0, .95))
      }));
      layer.appendChild(group);
    }

    function drawEnvelope(layer, pose, opacity, id) {
      const x = pose.envelopeX;
      const y = pose.envelopeY;
      const w = pose.envelopeW;
      const h = pose.envelopeH;
      const cx = x + w / 2;
      const cy = y + h / 2;
      const group = el("g", {
        id,
        "data-role": "catch-envelope-placeholder",
        transform: `rotate(${fmt(pose.envelopeRotate)} ${fmt(cx)} ${fmt(cy)})`,
        opacity
      });
      group.appendChild(el("rect", {
        x: fmt(x),
        y: fmt(y),
        width: fmt(w),
        height: fmt(h),
        rx: "2.5",
        fill: "#fffaf0",
        stroke: "#d8c7aa",
        "stroke-width": "3"
      }));
      const lines = [
        `M ${fmt(x + 3)} ${fmt(y + 6)} L ${fmt(cx)} ${fmt(y + h * .56)} L ${fmt(x + w - 3)} ${fmt(y + 6)}`,
        `M ${fmt(x + 4)} ${fmt(y + h - 4)} L ${fmt(x + w * .43)} ${fmt(y + h * .48)}`,
        `M ${fmt(x + w - 4)} ${fmt(y + h - 4)} L ${fmt(x + w * .57)} ${fmt(y + h * .48)}`
      ];
      lines.forEach((d) => group.appendChild(el("path", {
        d,
        fill: "none",
        stroke: "#d8c7aa",
        "stroke-width": "3",
        "stroke-linecap": "round",
        "stroke-linejoin": "round",
        opacity: ".9"
      })));
      group.appendChild(el("rect", {
        x: fmt(x + 4),
        y: fmt(y + 4),
        width: fmt(w - 8),
        height: fmt(h - 8),
        rx: "2",
        fill: "none",
        stroke: "#fff",
        "stroke-width": "1.2",
        opacity: ".45"
      }));
      layer.appendChild(group);
    }

    function drawEnvelopeTrail(layer, pose, opacity = 1) {
      const finalCx = FINAL.envelopeX + FINAL.envelopeW / 2;
      const finalCy = FINAL.envelopeY + FINAL.envelopeH / 2;
      const cx = pose.envelopeX + pose.envelopeW / 2;
      const cy = pose.envelopeY + pose.envelopeH / 2;
      layer.appendChild(el("path", {
        d: `M ${fmt(cx)} ${fmt(cy)} L ${fmt(finalCx)} ${fmt(finalCy)}`,
        fill: "none",
        stroke: "#d8c7aa",
        "stroke-width": "2",
        "stroke-dasharray": "8 7",
        "stroke-linecap": "round",
        opacity: fmt(.46 * opacity)
      }));
      drawEnvelope(layer, FINAL, .22 * opacity, "notification-envelope-final-ghost");
    }

    function drawHeadAxis(layer, pose) {
      const p = { x: pose.headPivotX, y: pose.headPivotY + pose.headLift };
      layer.appendChild(el("circle", {
        cx: fmt(p.x),
        cy: fmt(p.y),
        r: "6.5",
        fill: "#6d56a7",
        stroke: "#fffaf3",
        "stroke-width": "2",
        opacity: ".9"
      }));
      layer.appendChild(el("path", {
        d: `M ${fmt(p.x - 28)} ${fmt(p.y)} L ${fmt(p.x + 28)} ${fmt(p.y)}`,
        fill: "none",
        stroke: "#6d56a7",
        "stroke-width": "2",
        "stroke-linecap": "round",
        "stroke-dasharray": "6 5",
        opacity: ".65"
      }));
    }

    function drawFootContacts(layer, pose) {
      ["left", "right"].forEach((side) => {
        const origin = FOOT_ORIGINS[side];
        const x = origin.x + pose[`${side}FootX`];
        const y = origin.y + pose[`${side}FootY`] + 9;
        const color = side === state.tiptoeSide ? "#ad4938" : "#14776c";
        layer.appendChild(el("path", {
          d: `M ${fmt(x - 16)} ${fmt(y)} L ${fmt(x + 16)} ${fmt(y)}`,
          fill: "none",
          stroke: color,
          "stroke-width": side === state.tiptoeSide ? "2.5" : "2",
          "stroke-linecap": "round",
          opacity: ".75"
        }));
        if (!state.showLabels) return;
        const text = el("text", {
          x: fmt(x),
          y: fmt(y + 17),
          fill: color,
          "font-size": "12",
          "font-weight": "700",
          "text-anchor": "middle",
          "paint-order": "stroke",
          stroke: "#fffaf3",
          "stroke-width": "3"
        });
        text.textContent = side === state.tiptoeSide ? "踮脚接地" : "平脚接地";
        layer.appendChild(text);
      });
    }

    function el(tag, attrs = {}) {
      const node = document.createElementNS(NS, tag);
      for (const [key, value] of Object.entries(attrs)) {
        if (value !== null && value !== undefined) node.setAttribute(key, String(value));
      }
      return node;
    }

    function fmt(value) {
      return String(parseFloat(Number(value).toFixed(3)));
    }

    function clamp(value, min, max) {
      return Math.max(min, Math.min(max, value));
    }

    function snapshot(pose = currentPose()) {
      return {
        diagnostic: "notification-catch-full-motion-v1",
        source: "drafts/master/hamster-flat-layered-v18-noodle-hands.svg",
        leftTurnSource: "drafts/side-45/turn-idle-confirmed-v1 left-turn contract via V5 side reference and confirmed V15 anchors",
        finalPoseSource: "notification-catch-pose-v1 saved browser state",
        progressContract: "0 idle/offscreen mail; 24 left-turn look; 52 tuned micro-tiptoe catch peak; 74 saved settled catch pose; 88 held-envelope wave",
        timeline: TIMELINE,
        state: { ...state },
        final: { ...FINAL },
        currentPose: pose,
        markers: Object.fromEntries(Object.entries(markers).map(([side, data]) => [
          side,
          {
            root: roundPoint(data.root),
            tip: roundPoint(data.tip),
            bones: Object.fromEntries(data.bones.map(([label, point]) => [label, roundPoint(point)])),
            transform: data.transform
          }
        ])),
        status: "diagnostic-only; not confirmed"
      };
    }

    function roundPoint(point) {
      return { x: Number(fmt(point.x)), y: Number(fmt(point.y)) };
    }



  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", bootExport);
  } else {
    bootExport();
  }
})();
